import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

const Header = () => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [cartCount, setCartCount] = useState(0);
  const [isLoginBroken, setIsLoginBroken] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const toggleMobileMenu = () => {
    setMobileMenuOpen(!mobileMenuOpen);
  };

  const toggleSearch = () => {
    setSearchOpen(!searchOpen);
  };

  const handleSearch = (e) => {
    if (e.key === 'Enter') {
      // Handle search functionality
      console.log('Searching for:', e.target.value);
      setSearchOpen(false);
    }
  };

  const handleLMSLogin = () => {
    window.open('https://learn.shefsolutionsllc.com/login/index.php', '_blank', 'noopener,noreferrer');
  };

  const handleLoginRegister = () => {
    navigate('/login');
  };

  const handleProgramCheckout = (programName, price, duration) => {
    const programInfo = {
      name: programName,
      price: price,
      duration: duration
    };
    navigate('/checkout', { state: { program: programInfo } });
  };

  console.log('Header rendering, current path:', location.pathname);

  return (
    <header className="header">
      {/* Announcement Section - Redesigned */}
      <div style={{
        background: '#000000',
        width: '100%',
        padding: '8px 0',
        borderBottom: '1px solid rgba(255,255,255,0.1)',
        position: 'relative',
        overflow: 'hidden'
      }}>
        <div style={{
          maxWidth: '100%',
          margin: '0 auto',
          padding: '0 20px',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <div className="contact-info" style={{
            display: 'flex',
            gap: '30px',
            alignItems: 'center'
          }}>
            <a href="tel:+18888102434" style={{
              color: '#ffffff',
              textDecoration: 'none',
              fontSize: '13px',
              fontWeight: '500',
              transition: 'all 0.3s',
              display: 'flex',
              alignItems: 'center',
              gap: '8px',
              padding: '4px 12px',
              borderRadius: '20px',
              background: 'rgba(40, 167, 69, 0.1)',
              border: '1px solid rgba(40, 167, 69, 0.3)'
            }}>
              <i className="fas fa-phone" style={{ 
                color: '#28a745',
                fontSize: '12px'
              }}></i>
              <span>+1 (888) 810-2434</span>
            </a>
            <a href="mailto:info@skystates.com" style={{
              color: '#ffffff',
              textDecoration: 'none',
              fontSize: '13px',
              fontWeight: '500',
              transition: 'all 0.3s',
              display: 'flex',
              alignItems: 'center',
              gap: '8px',
              padding: '4px 12px',
              borderRadius: '20px',
              background: 'rgba(0, 123, 255, 0.1)',
