                e.preventDefault();
                if (!isLoginBroken) {
                  navigate('/login');
                }
              }}
              style={{
                color: '#007bff',
                padding: '6px 14px',
                border: '1px solid #007bff',
                borderRadius: '20px',
                textDecoration: 'none',
                fontSize: '13px',
                fontWeight: '500',
                transition: 'all 0.3s',
                display: 'inline-block',
                background: 'transparent',
                transform: isLoginBroken ? 'rotate(2deg) translateX(20px) translateY(100px)' : 'none',
                opacity: isLoginBroken ? '0' : '1',
                transformOrigin: 'top left',
